  ('social-worker-moex-01095', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關個案工作的發展脈絡，下列敘述何者正確？', '["因為佛洛伊德學說使社會工作專業反省貧窮、失業無法做個人性的單純歸因", "因為人類行為科學諸多學說出現，所以美國自1960至70年代開始重視機構責信（accountability）", "因為後現代主義與社工專業自我反思，而強調應建立案主與社工夥伴式專業關係", "目前個案工作採用的是生態觀點和系統理論，而不是綜融取向社會工作"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01096', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於「以證據為基礎的實務」之敘述，下列何者錯誤？', '["強調提升服務的效益，並免去資源浪費", "強調服務輸送的有效性，以最適當地滿足服務使用者的需求", "強調提升社會工作者運用研究結果與執行研究的能力", "強調書面工作手冊是培養社會工作者「以證據為基礎」服務能力的最好方法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01097', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '單案研究設計（single-systemdesign）乃是根據可衡量的目標與可達成的目的進行評估。有關單案 研究設計的敘述何者正確？', '["需要分為實驗組及控制組，以比較服務介入產生之差異", "需要進行隨機抽樣，以使研究結果更具推論性", "需要執行前測和後測，以觀察服務介入的進展", "家庭社會工作之評估不適合使用單案研究設計"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01098', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者屬於對案主認知功能的評估？①現實感  ②自殺意圖  ③情感性疾病  ④自我概念', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01099', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '會談是社會個案工作的主要工作方法，下列敘述何者錯誤？', '["會談過程中的對話與互動受到專業倫理的約束", "會談雖有基本共同的內容，但每個個案的會談內容仍保有一定程度的個別化", "每一次會談可達成有限的目的，多次會談累積後可達成服務目的", "參與會談的個案與社會工作者都需承擔開啟會談的責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01100', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '倫理決策是一個謹慎的過程，當社會工作者面對倫理困境時，下列那一項處理原則錯誤？', '["要充分了解社會工作者的法律責任與義務", "要同時考量倫理議題的脈絡與情境面向", "當不同價值間有所衝突時，以法律規範為最優先之考量", "過程中需記錄重要的倫理決策與判斷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
